// 现在遍历 allTokens 输出
  for (auto&& token : allTokens) {
    if (token->getChannel() == SYsULexer::HIDDEN)
      continue;

    size_t startIdx = token->getStartIndex();
    int line = charLine[startIdx];
    int col = charCol[startIdx];
    std::string filename = charFile[startIdx];

    bool startOfLine = false;
    bool leadingSpace = false;

    if (startIdx == 0) {
      startOfLine = true;
    } else {
      char prev = source[startIdx - 1];
      if (prev == '\n' || prev == '\r') {
        startOfLine = true;
      } else if (prev == ' ' || prev == '\t') {
        leadingSpace = true;
      }
    }

    // 对于 EOF token
    if (token->getType() == antlr4::Token::EOF) {
      // eof 行号列号为最后一个 token 行号，列号 + 1
      size_t lastIdx = source.size();
      line = charLine[lastIdx];
      col = charCol[lastIdx];
      filename = charFile[lastIdx];
      startOfLine = false;
      leadingSpace = false;
    }

    print_token(token, tokens, outFile, lexer, filename, line, col,
                startOfLine, leadingSpace);
  }

action.new_str:
// 现在遍历 allTokens 输出
  for (auto&& token : allTokens) {
    if (token->getChannel() == SYsULexer::HIDDEN)
      continue;

    size_t startIdx = token->getStartIndex();
    int line = charLine[startIdx];
    int col = charCol[startIdx];
    std::string filename = charFile[startIdx];

    bool startOfLine = false;
    bool leadingSpace = false;

    // 对于 EOF token，使用最后一个非 hidden token 的 stop index + 1
    if (token->getType() == antlr4::Token::EOF) {
      // 找到最后一个非 hidden、非 EOF 的 token
      size_t lastStopIdx = 0;
      for (auto it = allTokens.rbegin(); it != allTokens.rend(); ++it) {
        if ((*it)->getChannel() != SYsULexer::HIDDEN &&
            (*it)->getType() != antlr4::Token::EOF) {
          lastStopIdx = (*it)->getStopIndex();
          break;
        }
      }
      startIdx = lastStopIdx + 1;
      line = charLine[startIdx];
      col = charCol[startIdx];
      filename = charFile[startIdx];
      startOfLine = false;
      leadingSpace = false;
    } else {
      // 确定 StartOfLine 和 LeadingSpace
      if (startIdx == 0) {
        startOfLine = true;
      } else {
        // 向前跳过所有空白字符，找到第一个非空白字符
        size_t j = startIdx;
        bool hasLeadingWhitespace = false;
        while (j > 0 && (source[j - 1] == ' ' || source[j - 1] == '\t')) {
          hasLeadingWhitespace = true;
          j--;
        }
        if (j == 0 || source[j - 1] == '\n' || source[j - 1] == '\r') {
          startOfLine = true;
        }
        leadingSpace = hasLeadingWhitespace;
      }
    }

    print_token(token, tokens, outFile, lexer, filename, line, col,
                startOfLine, leadingSpace);
  }

